scwin.onpageload = function () {
    scwin.parentFrame = $c.win.getParent();
    scwin.vVehclNo = scwin.parentFrame.scwin.vVehclNo == null ? "" : scwin.parentFrame.scwin.vVehclNo;
    scwin.vVehclShortCd = scwin.parentFrame.scwin.vehclShortCd == null ? "" : scwin.parentFrame.scwin.vehclShortCd;
    scwin.vVehclNoHomeClsCd = scwin.parentFrame.scwin.vVehclNoHomeClsCd == null ? "" : scwin.parentFrame.scwin.vVehclNoHomeClsCd;
    scwin.vEqCd = scwin.parentFrame.scwin.vEqCd == null ? "" : scwin.parentFrame.scwin.vEqCd;
    //scwin.curDate = scwin.today;

    const codeOptions = [
        { grpCd: "ZZ205", compID: "gr_fixEquipment:eqHomeClsCd"},
        // { grpCd: "ZZ205", compID: "lux_sysCls, eqHomeClsCd", opt: { "range": "1,EQ" } },
        { grpCd: "ZZ202", compID: "lux_eqClssCd,eqClssCd" },//opt: { "range": "2,DS" } 미리 걸면 필터를 못한다.

        { grpCd: "ZZ201", compID: "eqClsCd" },
        { grpCd: "ZZ210", compID: "eqKndCd,eqKndCd2" },
        { grpCd: "ZZ203", compID: "gr_fixEquipment:posnClsCd,posnClsCd" },
        { grpCd: "ZZ622", compID: "purpsCd" },

        { grpCd: "ZZ105", compID: "regRgnCd", opt: { "range": "1,EQ,2" } },

        //{ grpCd: "ZZ210", compID: "eqKndCd2" },
        { grpCd: "ZZ208", compID: "eqStdCd" },
        { grpCd: "ZZ207", compID: "engdispCd" },

        { grpCd: "ZZ507", compID: "seatCnt" },

        { grpCd: "ZZ604", compID: "fuelKndCd" },
        { grpCd: "ZZ309", compID: "travelWayCd" },
        //{ grpCd: "EQ031", compID: "diffmodelCd", opt: { "upperCd": "21" } },
        //{ grpCd: "EQ031", compID: "trnsmModelCd", opt: { "upperCd": "03" } },
        //{ grpCd: "EQ031", compID: "ngModelCd", opt: { "upperCd": "01" } },
        { grpCd: "ZZ609", compID: "eqMakerCd" }
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function () {
    scwin.f_ContentsDisable();

    lux_qryCond.setSelectedIndex(2);
    scwin.txt_payIdx = "1";

    $c.gus.cfDisableBtn([b_Update,b_Update2, b_Cancel,b_Cancel2, b_Save,b_Save2]);

    //setFixEquipmentHeader();

    if ((scwin.vVehclNoHomeClsCd == "TR" || scwin.vVehclNoHomeClsCd == "LO") && scwin.vVehclNo.trim() != "") {
        scwin.f_Create();
        vehclNo.setValue(scwin.vVehclNo);
        vehclShortCd.setValue(scwin.vVehclShortCd);
    } else if (scwin.vVehclNo != "") {
        scwin.f_Retrieve1();
    } else {
        qryCntn.focus();
    }
}

scwin.ondataload = function () {
    // 위랑 옆이랑 같은 공통 코드인데 추가 노드가 위만
    let dltStr = "dlt_commonCodeZZ205"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    let dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    ds_commonCodeZZ205.setJSON(dlt.getAllJSON());
    ds_commonCodeZZ205_2.setJSON(dlt.getAllJSON());
    var filterOptions = {type:'row', colIndex:'fltrCd1', key:"EQ", condition:'and', exactMatch:true};
    ds_commonCodeZZ205.setColumnFilter(filterOptions);
    ds_commonCodeZZ205_2.setColumnFilter(filterOptions);

    lux_sysCls.addItem(0, '전체', 0); // 쿼리가 전체 0 값 비교 여서 choose 옵션으로 처리가 안됨
    lux_sysCls.setSelectedIndex(1);// 위에 노드 추가 하면 포커스가 전체로감


    //lux_eqClssCd,eqClssCd
    let dltStr202 = "dlt_commonCodeZZ202"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    let dlt202 = $c.gus.object(dltStr202); // 데이터 리스트 객체
    ds_commonCodeZZ202.setJSON(dlt202.getAllJSON());

    $c.data.dataListFilter(ds_commonCodeZZ202, "fltrCd2 == 'DS'");  //$c.data.dataListFilter 함수를 이용해서 필터
    lux_eqClssCd.setNodeSet('data:ds_commonCodeZZ202');

    let comCdEQ031U21 = $c.gus.gauceUtil("getGridComboByUpperCd", "EQ031", "21", true);
    let comCdEQ031U03 = $c.gus.gauceUtil("getGridComboByUpperCd", "EQ031", "03", true);
    let comCdEQ031U01 = $c.gus.gauceUtil("getGridComboByUpperCd", "EQ031", "01", true);

    ds_commonCodeEQ031U21.setJSON(comCdEQ031U21);
    ds_commonCodeEQ031U03.setJSON(comCdEQ031U03);
    ds_commonCodeEQ031U01.setJSON(comCdEQ031U01);

    //{ grpCd: "EQ031", compID: "diffmodelCd", opt: { "upperCd": "21" } },
    //{ grpCd: "EQ031", compID: "trnsmModelCd", opt: { "upperCd": "03" } },
    //{ grpCd: "EQ031", compID: "ngModelCd", opt: { "upperCd": "01" } },



    let dltStrZZ208 = "dlt_commonCodeZZ208"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    let dltZZ208 = $c.gus.object(dltStrZZ208); // 데이터 리스트 객체
    ds_commonCodeZZ208.setJSON(dltZZ208.getAllJSON());

    var option = {}
    option.sortIndex = "cdNm cd";
    option.sortOrder = "1 1";

    ds_commonCodeZZ208.multisort(option);
    eqStdCd.setNodeSet('data:ds_commonCodeZZ208');

}

