scwin.btn_reset_onclick = function (e) {
    $c.gus.cfInitObjects(tbl_search);
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.b_Create_onclick = function (e) {
    scwin.f_Create();
};

scwin.b_Update_onclick = function (e) {
    scwin.f_Update();
};

scwin.b_Cancel_onclick = function (e) {
    scwin.f_Cancel();
};

scwin.b_Save_onclick = function (e) {
    scwin.f_Save();
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
    scwin.f_ContentsEnable();

    $c.gus.cfEnableObj(crn, false); // 사업자등록번호

    $c.gus.cfEnableObj(eqClsCd, false); // 장비구분코드
    $c.gus.cfEnableObj(eqClssCd, false); // 장비분류코드
    $c.gus.cfEnableObj(eqKndCd, false); // 장비종류코드
    $c.gus.cfEnableObj(eqKndCd2, false); // 장비종류코드
    $c.gus.cfEnableObj(engdispCd, false); // 배기량코드
    $c.gus.cfEnableObj(eqMakerCd, false); // 제조사코드	
    $c.gus.cfEnableObj(fuelKndCd, false); // 연료종류코드

    scwin.txt_createYn = "1";
    scwin.txt_saveType = "0";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소

    let row;
    row = ds_fixEquipment.insertRow();
    ds_fixEquipment.setRowPosition(row);
    gr_fixEquipment.setFocusedCell(row, 0);


    //eqHomeClsCd.Index = 0;  // 장비소속
    posnClsCd.setSelectedIndex(0);   // 소유구분
    purpsCd.setSelectedIndex(0);   // 용도
    eqChgDt.setValue(scwin.today);		// 장비변경일자

    $c.gus.cfDisableBtn([b_Create,b_Create2, b_Update,b_Update2]);
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    scwin.f_ContentsEnable();

    $c.gus.cfEnableObj(crn, false); // 사업자등록번호

    scwin.txt_updateYn = "1";   // 수정인경우
    scwin.txt_saveType = "1";   // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    //  eqChgDt.text = curDate;      // 장비변경일자

    $c.gus.cfDisableBtn([b_Create,b_Create2, b_Update,b_Update2]);

    // 물류장비인 경우 검사예정일 수정 불가
    if (eqHomeClsCd.getValue() == "LO") {
        rglintChkExpireDt.setDisabled(true);
        rglintInspExpireDt.setDisabled(true);
        mntnInspExpireDt.setDisabled(true);

        //$c.gus.cfEnableObj(rglintchkexpiredt_cal, false);   // 정기점검만료일자 조회 이미지
        //$c.gus.cfEnableObj(rglintinspexpiredt_cal, false);  // 정기검사만료일자 조회 이미지
        //$c.gus.cfEnableObj(mntninspexpiredt_cal, false);    // 정밀검사만료일자 조회이미지
    }
};

//-------------------------------------------------------------------------
// 장비 등록, 수정 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    // 취소 확인
    scwin.f_ContentsDisable();

    if (ds_fixEquipment.getRowPosition() > ds_fixEquipment.getRowCount() || ds_fixEquipment.getModifiedIndex().length > 0) {
        //ds_fixEquipment.undo(ds_fixEquipment.getRowPosition());
        $c.data.undoRow(ds_fixEquipment, "Y");
    }

    $c.gus.cfDisableBtn([b_Cancel,b_Cancel2, b_Save,b_Save2]);

    scwin.txt_saveType = "4";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    let vRowStatus = ds_fixEquipment.getRowStatus(ds_fixEquipment.getRowPosition());
    let ret;

    // 필수항목 체크
    ret = await $c.gus.cfValidate([chkRegistInfo]);
    if (!ret) {
        return false;
    }


    // 필수항목 체크
    ret = await $c.gus.cfValidate([regData, eqChgDt]);
    if (!ret) {
        return false;
    }

    // ************************************
    // **** 최초등록일자에 대해서만 더블 체크 *****
    // ************************************
    ret = await $c.gus.cfValidate([firstRegDt]);
    if (!ret) {
        return false;
    }

    scwin.txt_saveType = "3"; // 타입이 저장

    //변경한 데이터가 있는지 체크한다. 
    if (ds_fixEquipment.getModifiedIndex().length === 0) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    if (vRowStatus === 'C') { // AsIs 1 create 
        let vCurrentRowVehclShortCd =
            ds_fixEquipment.getCellData(ds_fixEquipment.getRowPosition(), "vehclShortCd");

        lux_sysCls.setSelectedIndex(0);
        lux_qryCond.setSelectedIndex(2);
        qryCntn.setValue(vCurrentRowVehclShortCd);
    }

    // 저장확인 
    ret = await $c.win.confirm("저장하시겠습니까?");
    if (ret === true) {
        scwin.pos_groupCode = ds_fixEquipment.getRowPosition();

        let depositAdptClsCd =
            ds_fixEquipment.getCellData(scwin.pos_groupCode, "depositAdptClsCd");

        if (depositAdptClsCd && depositAdptClsCd.length === 6) {
            depositAdptClsCd =
                depositAdptClsCd.substring(0, 4) + "-" +
                depositAdptClsCd.substring(4, 6);

            ds_fixEquipment.setCellData(scwin.pos_groupCode, "depositAdptClsCd", depositAdptClsCd);
        }

        //tr_saveFixEquipment.Action ="/cm.bc.eq.eqmgnt.cmd.SaveFixEquipmentInformationCMD.do";
        //tr_saveFixEquipment.Post();
        $c.sbm.execute(sbm_saveFixEquipment);
    }
};

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_Undo = function () {
    //ds_fixEquipment.Undo(ds_fixEquipment.RowPosition);
    $c.data.undoRow(ds_fixEquipment, "Y");
}


// callbackfunc : _cb
scwin.udc_eqModelCd_cb = function (rtnList) {

    console.log('scwin.udc_eqModelCd_cb');
    console.log(rtnList);

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return false;

        eqModelCd.setValue(rtnList[0]);	//모델코드
        eqModelNm.setValue(rtnList[1]);	//모델명
        eqClsCd.setValue(rtnList[2]);  // 장비구분
        eqClssCd.setValue(rtnList[3]); // 장비분류
        eqKndCd.setValue(rtnList[4]);  // 장비종류
        eqKndCd2.setValue(rtnList[4]);  // 장비종류

        eqKndCd.setDisabled(true);
        eqKndCd2.setDisabled(true);

        engdispCd.setValue(rtnList[5]); // 배기량코드
        fuelKndCd.setValue(rtnList[6]); // 연료종류코드
        seatCnt.setValue(rtnList[7]);    // 좌석수
        eqMakerCd.setValue(rtnList[8]);  // 제조사

        if (rtnList[2].trim() == "LV") {
            eqHomeClsCd.setSelectedIndex(0);
        } else if (rtnList[2].trim() == "TV") {
            eqHomeClsCd.setSelectedIndex(1);
        }

    }
}

//-------------------------------------------------------------------------
// 장비모델팝업
//-------------------------------------------------------------------------
scwin.f_openEqModelPopUp = function () {
    let vEqHomeClsCd = eqHomeClsCd.getValue();
    let vInput = null;

    if (vEqHomeClsCd == "TR") {
        vInput = "TV";
    }

    //var rtnList = new Array();
    udc_eqModelCd.setSelectId("retrieveEqModelListInfo");
    udc_eqModelCd.cfCommonPopUp(scwin.udc_eqModelCd_cb, '', '', "T", null, null, "150,180", "3,4,5,6,7,8,9,10", vInput, null, null, null, null, null, null, null, null); //  장비모델팝업

}

scwin.udc_regLobranCd_cb = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return false;

        // 등록점소코드
        regLobranCd.setValue(rtnList[0]);	//등록점소코드
        regLobranNm.setValue(rtnList[1]);	//등록점소명
    }
}

//-------------------------------------------------------------------------
// 물류점소팝업 : 등록점소
//-------------------------------------------------------------------------
scwin.f_openLogisDeptPopUp = function () {

