    }    
    */
    let data = {};
    let popupResult;

    const options = {
        id: "newzipcodePopup",
        type: "popup",
        modal: true,
        popupName: "우편번호",
        width: 530,
        height: 400
    };
    popupResult = await $c.win.openPopup("/ui/cm/zz/newzipcodePopup.xml", options, data);

    if (popupResult != null) {
        useStrhldZip.setValue(popupResult.zip);
        useStrhldAddr1.setValue(popupResult.addr1);
        useStrhldAddr2.focus();
    } else {
        useStrhldZip.setValue("");
        useStrhldAddr1.setValue("");
        useStrhldAddr2.setValue("");
        useStrhldZip.focus();
    }
}

