scwin.eqHomeClsCd_onchange = function (info) {
    let vEqHomeClsCd = eqHomeClsCd.getValue();
    //let vEqClsCd = eqClsCd.getValue();
    let vEqClsCd = ds_fixEquipment.getCellData(ds_fixEquipment.getRowPosition(), 'eqClsCd');//위에가 타이밍상 안바뀌어 있다.

    //alert("vEqHomeClsCd = " + vEqHomeClsCd + ", vEqClsCd = " + vEqClsCd);
    if (vEqHomeClsCd == "LO") {
        scwin.txt_eqHomeClsCd = "LO";
        if (vEqClsCd != "" && vEqClsCd == "TV") {
            $c.win.alert("선택하신 장비모델은 물류장비모델이 아닙니다.");
            return false;
        }

    } else if (vEqClsCd != "" && vEqHomeClsCd == "TR") {
        scwin.txt_eqHomeClsCd = "TR";

        if (vEqClsCd != "TV") {
            $c.win.alert("선택하신 장비모델은 고속차량모델이 아닙니다.");
            return false;
        }
    } else if (vEqClsCd = "" && vEqHomeClsCd == "TR") {
        scwin.txt_eqHomeClsCd = "TR";
    }
};


scwin.sbm_saveFixEquipment_submitdone = function (e) {


    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        let vCountRow = ds_fixEquipment.getRowCount();

        if (scwin.txt_saveType == "0") {
            scwin.f_Retrieve();
        } else {
            scwin.f_ContentsDisable();

            if (vCountRow > 0) {
                $c.gus.cfDisableBtn([b_Cancel,b_Cancel2, b_Save,b_Save2]);
            } else {
                $c.gus.cfDisableBtn([b_Update,b_Update2, b_Cancel,b_Cancel2, b_Save,b_Save2]);
            }
        }
    }
}
scwin.sbm_saveFixEquipment_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
}

//-------------------------------------------------------------------------
// 정비 장비 조회(전체)
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    scwin.txt_saveType = "2";  // 0:신규, 1:수정, 2:조회

    let txt_qryCntn = qryCntn.getValue().trimAll();

    if (txt_qryCntn.length < 1) {
        msgArr = new Array(2);
        msgArr[0] = "검색어";
        msgArr[1] = "글자(숫자) 한(두)";
        $c.gus.cfAlertMsg(MSG_CM_ERR_011, msgArr);
        qryCntn.focus();
        return false;
    }

    let vEqDelYn = "0";

    if (chk_eqDelYn.getValue()) {
        vEqDelYn = "1";
    }

    let condition = "?";
    condition += "sysCls=" + lux_sysCls.getValue() + "&qryCond=" + lux_qryCond.getValue()
        + "&qryCntn=" + qryCntn.getValue() + "&eqClssCd=" + lux_eqClssCd.getValue() + "&eqDelYn=" + vEqDelYn;

    //eqDelYn sysCls qryCond

    //ds_fixEquipment.DataID = "/cm.bc.eq.eqmgnt.cmd.RetrieveFixEquipmentListCMD.do" + condition; 
    //ds_fixEquipment.Reset();
    ds_fixEquipment.removeAll();
    sbm_fixEquipment.action = "/cm.bc.eq.eqmgnt.cmd.RetrieveFixEquipmentListCMD.do" + condition;
    $c.sbm.execute(sbm_fixEquipment);

    //scwin.f_ContentsDisable();

    //$c.gus.cfDisableBtn([b_Cancel,b_Cancel2, b_Save,b_Save2]);

}
//<script language=JavaScript for=ds_fixEquipment event=OnLoadCompleted(rowCnt)>
scwin.sbm_fixEquipment_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        var len = e.responseJSON.GAUCE.length;
        if (len == 0) {
            $c.win.alert('조회된 데이터가 없습니다.');
            qryCntn.focus();
            ed_totalRows.setValue(0);
        } else {
            scwin.txt_eqCd = ds_fixEquipment.getCellData(0, "eqCd");
            scwin.txt_rowCount = ds_fixEquipment.getRowCount();
            $c.gus.cfGoPrevPosition(gr_fixEquipment, scwin.pos_groupCode);
            ed_totalRows.setValue(len);
        }
    } else {
        ed_totalRows.setValue(0);
    }
}
scwin.sbm_fixEquipment_submiterror = function (e) { }


//-------------------------------------------------------------------------
// 정비 장비 조회(법적조회에서 넘어온것 (1건에 대한 조회))
