scwin.f_Retrieve1 = function () {
    let condition = "?";
    condition += "sysCls=0" + "&qryCond=7"
        + "&qryCntn=" + scwin.vEqCd + "&eqClssCd=" + lux_eqClssCd.getValue() + "&eqDelYn=3";

