scwin.rqwr_formatter = function (a,b,c,d,e,f,g) {
    // ###/####
    var pVal = a.substr(0,3);
    var nVal = a.substr(3);
    if (pVal.length == 3) {
        if (nVal != "") {
            pVal = pVal + "/" + nVal;
        }
    }
    return pVal;
};
